mapper.select:

from knowledge_lib knowledgeLib


order by knowledgeLib.id desc
limit #{start},#{pageSize}

select knowledgeLib.* from knowledge_lib knowledgeLib
where not exists (
  select app.id from app app where app.user_id = #{userId} and app.lib_id = knowledgeLib.id
)
and knowledgeLib.user_id = #{userId}
order by knowledgeLib.id desc
